 1→import type { RecordId } from "surrealdb";
 2→import type { BrainAction } from "../oauth/types";
 3→import type { PolicyTraceEntry } from "../policy/types";
 4→import type { EvidenceVerificationResult } from "./evidence-types";
 5→
 6→export type { PolicyTraceEntry } from "../policy/types";
 7→
 8→// --- Intent Status (state machine states) ---
 9→
10→export type IntentStatus =
11→  | "draft"
12→  | "pending_auth"
13→  | "pending_veto"
14→  | "authorized"
15→  | "executing"
16→  | "completed"
17→  | "vetoed"
18→  | "failed";
19→
20→// --- Action Specification ---
21→
22→export type ActionSpec = {
23→  provider: string;
24→  action: string;
25→  params?: Record<string, unknown>;
26→};
27→
28→// --- Budget Limit ---
29→
30→export type BudgetLimit = {
31→  amount: number;
32→  currency: string;
33→};
34→
35→// --- Evaluation Result ---
36→
37→export type EvaluationResult = {
38→  decision: "APPROVE" | "REJECT";
39→  risk_score: number;
40→  reason: string;
41→  reasoning?: string;
42→};
43→
44→// --- Routing Decision (discriminated union) ---
45→
46→export type RoutingDecision =
47→  | { route: "auto_approve" }
48→  | { route: "veto_window"; expires_at: Date }
49→  | { route: "reject"; reason: string };
50→
51→// --- Intent Record ---
52→
53→export type IntentRecord = {
54→  id: RecordId<"intent", string>;
55→  goal: string;
56→  reasoning: string;
57→  status: IntentStatus;
58→  priority: number;
59→  action_spec: ActionSpec;
60→  budget_limit?: BudgetLimit;
61→  evaluation?: EvaluationResult & {
62→    evaluated_at: Date;
63→    policy_only: boolean;
64→    policy_trace?: PolicyTraceEntry[];
65→    human_veto_required?: boolean;
66→  };
67→  veto_expires_at?: Date;
