  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { evaluateIntent, createLlmEvaluator } from "./authorizer";
  3→import type { LlmEvaluator } from "./authorizer";
  4→import { updateIntentStatus, getIntentById } from "./intent-queries";
  5→import { routeByRisk } from "./risk-router";
  6→import type { IntentRecord, EvaluationResult } from "./types";
  7→import type { EvidenceEnforcementMode } from "./evidence-types";
  8→import type { ServerDependencies } from "../runtime/types";
  9→import {
 10→  findAlignedObjectivesSurreal,
 11→  createSupportsEdgeSurreal,
 12→  createAlignmentWarningObservation,
 13→} from "../objective/alignment-adapter";
 14→
 15→type EvaluatePendingIntentDeps = {
 16→  surreal: Surreal;
 17→  extractionModel?: ServerDependencies["extractionModel"];
 18→  llmEvaluator?: LlmEvaluator;
 19→};
 20→
 21→type EvaluatedStatus = "authorized" | "pending_veto" | "vetoed";
 22→
 23→type EvaluatedIntent = {
 24→  intentId: string;
 25→  status: EvaluatedStatus;
 26→  evaluation: EvaluationResult & {
 27→    evaluated_at: Date;
 28→    policy_only: boolean;
 29→    policy_trace?: import("../policy/types").PolicyTraceEntry[];
 30→    human_veto_required?: boolean;
 31→  };
 32→  vetoExpiresAt?: Date;
 33→};
 34→
 35→type EvaluatePendingIntentResult =
 36→  | { ok: true; value: EvaluatedIntent }
 37→  | { ok: false; error: string; httpStatus: number };
 38→
 39→type EvaluatePendingIntentOptions = {
 40→  intent?: IntentRecord;
 41→};
 42→
 43→function resolveRecordId<T extends string>(
 44→  table: T,
 45→  ref: unknown,
 46→): RecordId<T> {
 47→  const rawId = typeof ref === "object" && ref !== null
 48→    ? ((ref as { id: unknown }).id as string)
 49→    : String(ref);
 50→  return new RecordId(table, rawId);
 51→}
 52→
 53→type TransitionPlan = {
 54→  targetStatus: EvaluatedStatus;
 55→  updateFields: Record<string, unknown>;
 56→  status: EvaluatedStatus;
 57→  vetoExpiresAt?: Date;
 58→};
 59→
 60→function toTransition(
 61→  routing: ReturnType<typeof routeByRisk>,
 62→  evaluationRecord: EvaluatedIntent["evaluation"],
 63→): TransitionPlan {
 64→  switch (routing.route) {
 65→    case "auto_approve":
 66→      return {
 67→        targetStatus: "authorized",
 68→        status: "authorized",
 69→        updateFields: { evaluation: evaluationRecord },
 70→      };
 71→    case "veto_window":
 72→      return {
 73→        targetStatus: "pending_veto",
 74→        status: "pending_veto",
 75→        updateFields: { evaluation: evaluationRecord, veto_expires_at: routing.expires_at },
 76→        vetoExpiresAt: routing.expires_at,
 77→      };
 78→    case "reject":
 79→      return {
 80→        targetStatus: "vetoed",
 81→        status: "vetoed",
 82→        updateFields: { evaluation: evaluationRecord },
 83→      };
 84→  }
 85→}
 86→
 87→export async function evaluatePendingIntent(
 88→  intentId: string,
 89→  deps: EvaluatePendingIntentDeps,
 90→  options?: EvaluatePendingIntentOptions,
 91→): Promise<EvaluatePendingIntentResult> {
 92→  const intent = options?.intent ?? await getIntentById(deps.surreal, intentId);
 93→  if (!intent) {
 94→    return { ok: false, error: "Intent not found", httpStatus: 404 };
 95→  }
 96→
 97→  if (intent.status !== "pending_auth") {
 98→    return {
 99→      ok: false,
100→      error: `Intent is in '${intent.status}' status, expected 'pending_auth'`,
101→      httpStatus: 409,
102→    };
103→  }
104→
105→  const identityId = resolveRecordId("identity", intent.requester);
106→  const workspaceRecord = resolveRecordId("workspace", intent.workspace);
107→  const intentRecord = new RecordId("intent", intentId);
108→
109→  const [identityRows] = await deps.surreal.query<[Array<{ type?: string; role?: string }>]>(
110→    `SELECT type, role FROM $identity;`,
111→    { identity: identityId },
112→  );
113→  const identityInfo = identityRows[0];
114→
115→  const llmEvaluator = deps.llmEvaluator
116→    ?? (deps.extractionModel ? createLlmEvaluator(deps.extractionModel) : undefined);
117→  if (!llmEvaluator) {
118→    return { ok: false, error: "Missing evaluator model", httpStatus: 500 };
119→  }
120→
121→  // Read workspace evidence enforcement mode
122→  let evidenceEnforcementMode: EvidenceEnforcementMode = "bootstrap";
123→  try {
124→    const [wsRows] = await deps.surreal.query<[Array<{ evidence_enforcement?: string }>]>(
125→      `SELECT evidence_enforcement FROM $ws;`,
126→      { ws: workspaceRecord },
127→    );
128→    evidenceEnforcementMode =
129→      (wsRows[0]?.evidence_enforcement as EvidenceEnforcementMode) ?? "bootstrap";
130→  } catch {
131→    // Default to bootstrap if enforcement mode cannot be read
132→  }
133→
134→  const evaluation = await evaluateIntent({
135→    intent: {
136→      goal: intent.goal,
137→      reasoning: intent.reasoning,
138→      action_spec: intent.action_spec,
139→      budget_limit: intent.budget_limit,
140→      priority: intent.priority,
141→    },
142→    surreal: deps.surreal,
143→    identityId,
144→    workspaceId: workspaceRecord,
145→    requesterType: identityInfo?.type ?? "agent",
146→    requesterRole: identityInfo?.role,
147→    llmEvaluator,
148→    intentId: intentRecord,
149→    intentText: intent.goal,
150→    findAlignedObjectives: findAlignedObjectivesSurreal(deps.surreal),
151→    createSupportsEdge: createSupportsEdgeSurreal(deps.surreal),
152→    createAlignmentWarning: (ws, iId, score) =>
153→      createAlignmentWarningObservation(deps.surreal, ws, iId, score),
154→    evidenceRefs: intent.evidence_refs,
155→    evidenceEnforcementMode,
156→  });
157→
158→  // Strip `alignment` and `evidence_verification` — they are stored separately
159→  const { alignment: _alignment, evidence_verification, ...evaluationForDb } = evaluation;
160→  const evaluationRecord: EvaluatedIntent["evaluation"] = {
161→    ...evaluationForDb,
162→    evaluated_at: new Date(),
163→  };
164→  const routing = routeByRisk(evaluation, {
165→    humanVetoRequired: evaluation.human_veto_required,
166→  });
167→  const transition = toTransition(routing, evaluationRecord);
168→
169→  // Include evidence_verification in the status update
170→  if (evidence_verification) {
171→    transition.updateFields.evidence_verification = evidence_verification;
172→  }
173→
174→  const result = await updateIntentStatus(
175→    deps.surreal,
176→    intentId,
177→    transition.targetStatus,
178→    transition.updateFields,
179→  );
180→  if (!result.ok) {
181→    return { ok: false, error: result.error, httpStatus: 409 };
182→  }
183→
184→  return {
185→    ok: true,
186→    value: {
187→      intentId,
188→      status: transition.status,
189→      evaluation: evaluationRecord,
190→      ...(transition.vetoExpiresAt ? { vetoExpiresAt: transition.vetoExpiresAt } : {}),
191→    },
192→  };
193→}
