133→export async function updateIntentStatus(
134→  surreal: Surreal,
135→  intentId: string,
136→  newStatus: IntentStatus,
137→  updates?: StatusUpdateFields,
138→): Promise<{ ok: true; record: IntentRecord } | { ok: false; error: string }> {
139→  const existing = await getIntentById(surreal, intentId);
140→  if (!existing) {
141→    return { ok: false, error: `Intent ${intentId} not found` };
142→  }
143→
144→  const transition = transitionStatus(existing.status, newStatus);
145→  if (!transition.ok) {
146→    return { ok: false, error: transition.error };
147→  }
148→
149→  const record = new RecordId("intent", intentId);
150→  const now = new Date();
151→
152→  const setFields: Record<string, unknown> = {
153→    status: newStatus,
154→    updated_at: now,
155→  };
156→
157→  if (updates?.evaluation) {
158→    setFields.evaluation = updates.evaluation;
159→  }
160→  if (updates?.veto_expires_at) {
161→    setFields.veto_expires_at = updates.veto_expires_at;
162→  }
163→  if (updates?.veto_reason) {
164→    setFields.veto_reason = updates.veto_reason;
165→  }
166→  if (updates?.error_reason) {
167→    setFields.error_reason = updates.error_reason;
168→  }
169→  if (updates?.evidence_verification) {
170→    setFields.evidence_verification = updates.evidence_verification;
171→  }
172→
173→  const [rows] = await surreal.query<[IntentRecord[]]>(
174→    "UPDATE $record MERGE $fields RETURN AFTER;",
175→    {
176→      record,
177→      fields: setFields,
178→    },
179→  );
180→
181→  return { ok: true, record: rows[0] };
182→}
